import React, { useState } from 'react';
import { chatWithAI } from '../services/aiService';

// Page: AI Chatbot
// Maintains a local conversation history and sends it to the backend for multi-turn responses.
const AIChatbot = () => {
  const systemPrompt = `You are an expert in freelance client acquisition, proposal writing, pricing strategy (Indian ₹ market), tech stack advice, and client objection handling. Be conversational and helpful.`;
  const [conversation, setConversation] = useState([]);
  const [input, setInput] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const sendMessage = async () => {
    if (!input.trim()) return;
    
    const userMsg = { role: 'user', content: input };
    const newConv = [...conversation, userMsg];
    setConversation(newConv);
    setInput('');
    setLoading(true);
    setError('');
    
    const res = await chatWithAI(newConv, systemPrompt);
    
    if (res.success) {
      const assistantMsg = { role: 'assistant', content: res.response };
      setConversation((c) => [...c, assistantMsg]);
    } else {
      setError(res.error);
      // Remove the failed user message to keep state clean
      setConversation((c) => c.slice(0, -1));
    }
    setLoading(false);
  };

  const quickReplies = [
    'How to price a 3-month web app project?',
    'Write a short cold outreach for SaaS startups in India',
    'How to handle scope creep?',
  ];

  return (
    <div style={{ padding: 20 }}>
      <h2>AI Assistant</h2>
      {error && <p style={{ color: 'red' }}>{error}</p>}
      
      <div style={{ border: '1px solid #ddd', padding: 10, height: 400, overflow: 'auto', marginBottom: 10 }}>
        {conversation.length === 0 && <p style={{ color: '#999' }}>Start a conversation below...</p>}
        {conversation.map((m, i) => (
          <div key={i} style={{ margin: 8, padding: 8, backgroundColor: m.role === 'user' ? '#e3f2fd' : '#f5f5f5', borderRadius: 4 }}>
            <strong>{m.role === 'user' ? '📝 You' : '🤖 Assistant'}:</strong>
            <div style={{ marginTop: 4 }}>{m.content}</div>
          </div>
        ))}
        {loading && <p style={{ color: '#999', fontStyle: 'italic' }}>Assistant is thinking...</p>}
      </div>

      <div style={{ marginBottom: 10 }}>
        <strong>Quick questions:</strong>
        <div>
          {quickReplies.map((q) => (
            <button
              key={q}
              style={{
                marginRight: 8,
                marginTop: 4,
                padding: '4px 8px',
                fontSize: '12px',
                backgroundColor: '#f0f0f0',
                border: '1px solid #ddd',
                borderRadius: 4,
                cursor: 'pointer',
              }}
              onClick={() => setInput(q)}
            >
              {q}
            </button>
          ))}
        </div>
      </div>

      <div style={{ display: 'flex', gap: 8 }}>
        <input
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyPress={(e) => e.key === 'Enter' && !loading && sendMessage()}
          placeholder="Ask the assistant..."
          style={{ flex: 1, padding: 8, fontSize: 14 }}
          disabled={loading}
        />
        <button onClick={sendMessage} disabled={loading} style={{ padding: '8px 16px' }}>
          {loading ? 'Thinking...' : 'Send'}
        </button>
      </div>
    </div>
  );
};

export default AIChatbot;
